export const getDonorsGetMatchingRequestsUrl = (params?: DonorsGetMatchingRequestsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/v1/donors/requests?${stringifiedParams}` : `/api/v1/donors/requests`
}

